import{_ as t,c as e,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Функции платформы: обзор планов и кода | Plannotator","description":"Изучите функции платформы Plannotator, включая обзор планов и обзор кода. Освойте основные навыки визуального обзора, добавления аннотаций и разметки изображений.","frontmatter":{"title":"Функции платформы: обзор планов и кода | Plannotator","sidebarTitle":"Обзор планов и кода","subtitle":"Функции платформы: обзор планов и кода","description":"Изучите функции платформы Plannotator, включая обзор планов и обзор кода. Освойте основные навыки визуального обзора, добавления аннотаций и разметки изображений.","order":2},"headers":[],"relativePath":"ru/backnotprop/plannotator/platforms/index.md","filePath":"ru/backnotprop/plannotator/platforms/index.md"}'),o={name:"ru/backnotprop/plannotator/platforms/index.md"};function n(l,a,d,s,h,c){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="функции-платформы" tabindex="-1">Функции платформы <a class="header-anchor" href="#функции-платформы" aria-label="Permalink to &quot;Функции платформы&quot;">​</a></h1><p>В этой главе представлены две ключевые функции Plannotator: <strong>обзор планов</strong> и <strong>обзор кода</strong>. Вы научитесь визуально просматривать планы, созданные ИИ, добавлять различные типы аннотаций, прикреплять изображения с разметкой и проверять изменения кода через git diff.</p><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом убедитесь</p><p>Прежде чем приступить к изучению этой главы, убедитесь, что вы выполнили следующие подготовительные шаги:</p><ul><li>✅ Завершили обучение по <a href="./../start/getting-started/">быстрому старту</a></li><li>✅ Установили плагин Plannotator (<a href="./../start/installation-claude-code/">Claude Code</a> или <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><h3 id="обзор-планов" tabindex="-1">Обзор планов <a class="header-anchor" href="#обзор-планов" aria-label="Permalink to &quot;Обзор планов&quot;">​</a></h3><p>Узнайте, как проверять планы выполнения, созданные ИИ, добавлять предложения по изменениям и заставить ИИ действовать в соответствии с вашими намерениями.</p><table tabindex="0"><thead><tr><th>Учебный материал</th><th>Описание</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">Основы обзора планов</a></td><td>Научитесь визуально просматривать планы, созданные ИИ, включая утверждение или отклонение планов</td></tr><tr><td><a href="./plan-review-annotations/">Добавление аннотаций к планам</a></td><td>Освойте добавление различных типов аннотаций в планы (удаление, замена, вставка, комментарий)</td></tr><tr><td><a href="./plan-review-images/">Добавление разметки изображений</a></td><td>Научитесь прикреплять изображения к обзору планов и использовать инструменты рисования, стрелки и круги для разметки</td></tr></tbody></table><h3 id="обзор-кода" tabindex="-1">Обзор кода <a class="header-anchor" href="#обзор-кода" aria-label="Permalink to &quot;Обзор кода&quot;">​</a></h3><p>Узнайте, как проверять изменения кода, добавлять построчные комментарии и находить проблемы перед фиксацией.</p><table tabindex="0"><thead><tr><th>Учебный материал</th><th>Описание</th></tr></thead><tbody><tr><td><a href="./code-review-annotations/">Добавление комментариев к коду</a></td><td>Освойте добавление построчных комментариев при обзоре кода (comment/suggestion/concern)</td></tr><tr><td><a href="./code-review-diff-types/">Переключение типов diff</a></td><td>Научитесь переключаться между различными типами diff (uncommitted/staged/last commit/branch) в обзоре кода</td></tr></tbody></table><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Рекомендуемый порядок обучения</p><p>В зависимости от вашего сценария использования, выберите подходящий путь обучения:</p><p><strong>Путь A: Приоритет обзора планов</strong> (рекомендуется для начинающих)</p><ol><li><a href="./plan-review-basics/">Основы обзора планов</a> → Сначала изучите базовый процесс обзора планов</li><li><a href="./plan-review-annotations/">Добавление аннотаций к планам</a> → Научитесь точно изменять планы</li><li><a href="./plan-review-images/">Добавление разметки изображений</a> → Используйте изображения для более четкого выражения намерений</li><li>Затем изучите серию обзора кода</li></ol><p><strong>Путь B: Приоритет обзора кода</strong> (для разработчиков с опытом code review)</p><ol><li><a href="./code-review-basics/">Основы обзора кода</a> → Ознакомьтесь с интерфейсом обзора кода</li><li><a href="./code-review-annotations/">Добавление комментариев к коду</a> → Изучите построчные комментарии</li><li><a href="./code-review-diff-types/">Переключение типов diff</a> → Освойте различные типы diff</li><li>Затем изучите серию обзора планов</li></ol></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить изучение:</p><ul><li><a href="./../advanced/url-sharing/">Обмен по URL</a> — Делитесь планами и аннотациями через URL для командной работы</li><li><a href="./../advanced/obsidian-integration/">Интеграция с Obsidian</a> — Автоматически сохраняйте утвержденные планы в Obsidian</li><li><a href="./../advanced/remote-mode/">Удаленный режим</a> — Используйте Plannotator в средах SSH, devcontainer, WSL</li></ul>',16)])])}const b=t(o,[["render",n]]);export{f as __pageData,b as default};
